package br.com.portfolio.ecommerce.inventory.infrastructure.persistence;
import br.com.portfolio.ecommerce.inventory.application.port.out.InventoryRepository; import br.com.portfolio.ecommerce.inventory.domain.InventoryItem; import org.springframework.stereotype.Repository; import java.util.*;
@Repository public class InventoryRepositoryAdapter implements InventoryRepository { private final InventoryJpaRepository repo; public InventoryRepositoryAdapter(InventoryJpaRepository repo){this.repo=repo;} public Optional<InventoryItem> findByProductIdForUpdate(UUID productId){return repo.findByProductIdForUpdate(productId).map(e->new InventoryItem(e.getProductId(),e.getAvailableQuantity()));} public void save(InventoryItem item){ var e=repo.findById(item.productId()).orElse(new InventoryJpaEntity(item.productId(), item.available())); e.setAvailableQuantity(item.available()); repo.save(e);} }
